INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('dietitian-moex-04724', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王先生50歲因疝氣入院手術。在手術時發現部分小腸缺血壞死，因此在疝氣手術完成後先暫 時關閉腹腔，五天後再次手術切除30公分空腸。病人主訴腹痛，理學檢查後腹脹、無腸音， 下肢有嚴重的按壓性水腫。其身高175公分、體重125公斤，相關血液檢查如下：albumin1.8 g/dL，Na138mmol/dL，K3.2mmol/dL，Cl102mmol/dL，下列敘述何者錯誤？', '["術前5～7天應該開始給予靜脈營養支持", "術後可給予含有arginine的免疫調節配方以降低傷口合併症", "其熱量需求為11～14kcal/kgidealbodyweight", "其蛋白質需求為2～2.5g/kgidealbodyweight"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04725', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '蔡先生是一位漁工，在船上進行收鋼纜作業時，因纜繩斷裂刷過大腿，使得右側大腿瞬間被 鋼纜切斷，被直升機緊急送到醫院，病人因敗血症與呼吸衰竭在急診急救後轉送外科加護病 房。在此階段，有關體內蛋白質代謝方式的敘述，下列何者錯誤？', '["支鏈胺基酸從骨骼肌分解氧化以提供能量來源", "肝臟分泌acute-phaseprotein 用以應付發炎反應與合成瘦體組織", "肌肉蛋白質分解後的胺基酸的碳骨架用以進行glucose-alaninecycle與glutaminesynthesis", "組織蛋白質分解使得鉀、磷、鎂從尿中排除"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04726', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '承上題，蔡先生在加護病房中因血液動力學（hemodynamics）一直不穩定，維持 NPO 的狀 態，但血糖一直高居300～400mg/dL之間，需以胰島素治療，此時關於導致蔡先生高血糖的 原因，下列敘述何者錯誤？', '["壓力荷爾蒙使得insulintoglucagon的比值增加", "因體內能量需求增加使得gluconeogenesis作用上升", "corticosteroid分泌促使體內蛋白質異化（proteolysis）增加", "發炎反應促使細胞激素分泌使得胰島素阻抗增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04727', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '罹患頑固型氣喘（refractoryasthma）當規律性使用類固醇治療時，宜補充下列何種營養素？', '["維生素B", "omega-6多元不飽和脂肪酸", "鈣", "維生素K"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04728', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關囊腫性纖維化（cysticfibrosis）病人的營養治療，下列敘述何者錯誤？', '["熱量需求為同年齡層健康族群的120～150%", "需補充維生素D （cholecalciferol），劑量為每日1,500～2,000IU，18歲以上劑量需增加至 3 每日10,000IU", "維生素K每日至少攝取1,000微克以達到最佳維生素K營養狀況", "病人常有血鈉過高的問題，應特別注意避免鈉攝取過高"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04729', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', 'Tumor-node-metastasis（TNM）的分類標準中，關於T1、T2、T3、T4所代表的意思，下列何者 正確？', '["主要腫瘤的大小", "主要腫瘤的數量", "主要腫瘤的種類", "主要腫瘤轉移到幾個器官"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04730', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關糖和甜味劑的敘述，下列何者正確？', '["高糖飲食對增加癌症的發病率沒有相關", "美國FDA批准的非營養性甜味劑，適度使用是安全的", "營養性甜味劑幾乎沒有提供能量，因為僅微量就可增甜", "糖醇類，如：甘露醇、山梨糖醇和木糖醇等，是屬於非營養性甜味劑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04731', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列何者不是腦性麻痺嬰兒常出現的問題？', '["骨質疏鬆", "便秘", "食慾增加", "胃食道逆流"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04732', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關Downsyndrome的孩童照顧，下列何者錯誤？', '["嬰兒期可能因為口腔運動技能無法協調，需提供腸道營養來達到營養需求", "可能因為減少肌肉張力及低活動度而增加肥胖的機會", "5歲以上的兒童，能量需求的計算必須基於體重而不是身高", "經常出現便秘問題，建議攝取足夠的纖維及水"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04733', 'dietitian', 'dietitian-moex-112-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '老化引起的胃酸不足（achlorhydria）是老年人易缺乏那一營養素的重要原因？', '["維生素B", "維生素B", "維生素B", "維生素B"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "88d3ba6901fa", "answer_pdf_sha1": "d81a306bb003", "source_family": "moex-gov-tw", "moex": {"exam_code": "112110", "c": "101", "s": "0103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "112", "exam_name": "112年第二次專技人員高等考試營養師、護理師、社會工作師考試、112年專技人員高等考試法醫師、語言治療師、聽力師、牙體技術師、公共衛生師考試...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
